package com.alibabacloud.bankingapp;

import android.os.Bundle;
import androidx.appcompat.app.AppCompatActivity;
import android.widget.Button;
import android.widget.EditText;
import android.widget.TextView;
import android.widget.Toast;

public class TransactionActivity extends AppCompatActivity {

    private EditText amountEditText;
    private Button processTransactionButton;
    private TextView accountBalanceTextView;
    private double accountBalance = 1000.0; // Initial balance

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_transaction);

        amountEditText = findViewById(R.id.amountEditText);
        processTransactionButton = findViewById(R.id.processTransactionButton);
        accountBalanceTextView = findViewById(R.id.accountBalanceTextView);

        updateAccountBalanceDisplay();

        processTransactionButton.setOnClickListener(v -> {
            String amountStr = amountEditText.getText().toString();
            if (!amountStr.isEmpty()) {
                double transactionAmount = Double.parseDouble(amountStr);
                if (transactionAmount > 0 && transactionAmount <= accountBalance) {
                    accountBalance -= transactionAmount;
                    updateAccountBalanceDisplay();
                    Toast.makeText(TransactionActivity.this, "Transaction processed successfully", Toast.LENGTH_SHORT).show();
                } else {
                    Toast.makeText(TransactionActivity.this, "Invalid amount or insufficient balance", Toast.LENGTH_SHORT).show();
                }
            } else {
                Toast.makeText(TransactionActivity.this, "Please enter a valid amount", Toast.LENGTH_SHORT).show();
            }
        });
    }

    private void updateAccountBalanceDisplay() {
        accountBalanceTextView.setText("Account Balance: $" + String.format("%.2f", accountBalance));
    }
}